#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    return (*(int*)a) - (*(int*)b);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        int *sorted = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) {
            scanf("%d", &a[i]);
            sorted[i] = a[i];
        }
        qsort(sorted, N, sizeof(int), cmp);
        int *stack = (int*)malloc(N * sizeof(int));
        int top = -1, idx = 0;
        for (int i = 0; i < N; ++i) {
            stack[++top] = a[i];
            while (top >= 0 && stack[top] == sorted[idx]) {
                --top; ++idx;
            }
        }
        if (idx == N) printf("YES\n"); else printf("NO\n");
        free(a); free(sorted); free(stack);
    }
    return 0;
}

