#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        sorted_a = sorted(a)
        stack = []
        idx = 0
        for x in a:
            stack.append(x)
            while stack and stack[-1] == sorted_a[idx]:
                stack.pop()
                idx += 1
                if idx == N:
                    break
        out_lines.append("YES" if idx == N else "NO")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

